import { createMemoryHistory, createRouter, type RouteRecordRaw } from 'vue-router';

// 移动端视图（懒加载）
const Dashboard = () => import('./views/Dashboard.vue');
const Profile = () => import('./views/Profile.vue');
const Characters = () => import('./views/Characters.vue');
const Romance = () => import('./views/Romance.vue');
const Faction = () => import('./views/Faction.vue');
const AssetsSecrets = () => import('./views/AssetsSecrets.vue');
const Opportunities = () => import('./views/Opportunities.vue');
const Variables = () => import('./views/Variables.vue');
const Settings = () => import('./views/Settings.vue');
const StartupInfo = () => import('./views/StartupInfo.vue');

// 开局模式路由
export const startupRoutes: RouteRecordRaw[] = [
  {
    path: '/startup-info',
    name: 'startup-info',
    component: StartupInfo,
    meta: { title: '开局信息', icon: 'fa-scroll', theme: 'startup' },
  },
  {
    path: '/variables',
    name: 'variables-startup',
    component: Variables,
    meta: { title: '全量变量', icon: 'fa-database', theme: 'variables' },
  },
];

// 正常游戏模式路由
export const routes: RouteRecordRaw[] = [
  {
    path: '/',
    name: 'dashboard',
    component: Dashboard,
    meta: { title: '仪表盘', icon: 'fa-gauge-high', theme: 'default' },
  },
  {
    path: '/profile',
    name: 'profile',
    component: Profile,
    meta: { title: '个人档案', icon: 'fa-id-card', theme: 'profile' },
  },
  {
    path: '/characters',
    name: 'characters',
    component: Characters,
    meta: { title: '人物库', icon: 'fa-users', theme: 'characters' },
  },
  {
    path: '/romance',
    name: 'romance',
    component: Romance,
    meta: { title: '绯色互动', icon: 'fa-heart', theme: 'romance' },
  },
  {
    path: '/faction',
    name: 'faction',
    component: Faction,
    meta: { title: '派系图谱', icon: 'fa-sitemap', theme: 'faction' },
  },
  {
    path: '/assets-secrets',
    name: 'assets-secrets',
    component: AssetsSecrets,
    meta: { title: '资产暗账', icon: 'fa-vault', theme: 'assets' },
  },
  {
    path: '/opportunities',
    name: 'opportunities',
    component: Opportunities,
    meta: { title: '机遇与危机', icon: 'fa-scale-balanced', theme: 'opportunities' },
  },
  {
    path: '/variables',
    name: 'variables',
    component: Variables,
    meta: { title: '全量变量', icon: 'fa-database', theme: 'variables' },
  },
];

export const settingsRoute: RouteRecordRaw = {
  path: '/settings',
  name: 'settings',
  component: Settings,
  meta: { title: '设置', icon: 'fa-cog', theme: 'settings' },
};

export const allRoutes: RouteRecordRaw[] = [...routes, ...startupRoutes, settingsRoute];

const router = createRouter({
  history: createMemoryHistory(),
  routes: allRoutes,
});

export default router;
